// ===== المرحلة 1: قراءة قائمة الملفات من File API =====
// نستخدم $helpers.httpRequest المتاحة في n8n
const FILE_API = 'http://host.docker.internal:8765';
const INBOX_PATH = 'D:\\SaleHSaaS3\\url_inbox';

let listResponse;
try {
  listResponse = await $helpers.httpRequest({
    method: 'GET',
    url: `${FILE_API}/list`,
    qs: { path: INBOX_PATH, extensions: '.txt,.url,.md' }
  });
} catch(e) {
  return [{ json: { skip: true, error: 'File API غير متاح: ' + e.message } }];
}

const files = listResponse.files || [];
if (files.length === 0) {
  return [{ json: { skip: true, message: 'لا توجد ملفات في url_inbox' } }];
}

// ===== المرحلة 2: قراءة كل ملف واستخراج الروابط =====
const results = [];

for (const file of files) {
  const fileName = file.fileName;
  const filePath = file.filePath;

  // قراءة محتوى الملف
  let readResponse;
  try {
    readResponse = await $helpers.httpRequest({
      method: 'GET',
      url: `${FILE_API}/read`,
      qs: { path: filePath }
    });
  } catch(e) {
    continue; // تجاهل الملف إذا فشلت القراءة
  }

  const content = readResponse.content || '';
  const lines = content.split('\n').map(l => l.trim()).filter(l => l.length > 0);
  const urls = lines.filter(l => l.startsWith('http://') || l.startsWith('https://'));

  if (urls.length === 0) continue;

  const title = fileName.replace(/\.(txt|url|md)$/i, '').replace(/[_-]/g, ' ');

  for (let i = 0; i < urls.length; i++) {
    results.push({
      json: {
        url: urls[i],
        title: urls.length > 1 ? `${title} (${i + 1})` : title,
        fileName,
        filePath,
        totalUrls: urls.length
      }
    });
  }
}

if (results.length === 0) {
  return [{ json: { skip: true, message: 'لا توجد روابط صالحة في أي ملف' } }];
}

return results;

const { url, title } = $input.first().json;

let type = 'webpage';
if (url.includes('youtube.com') || url.includes('youtu.be')) type = 'youtube';
else if (url.includes('twitter.com') || url.includes('x.com')) type = 'twitter';
else if (url.includes('linkedin.com')) type = 'linkedin';
else if (url.includes('facebook.com') || url.includes('fb.com')) type = 'facebook';
else if (url.includes('instagram.com')) type = 'instagram';
else if (url.includes('tiktok.com')) type = 'tiktok';
else if (url.includes('reddit.com')) type = 'reddit';
else if (url.match(/\.(mp3|wav|ogg|m4a|aac)$/i)) type = 'audio';
else if (url.match(/\.(mp4|avi|mov|mkv|webm)$/i)) type = 'video';
else if (url.match(/\.pdf$/i)) type = 'pdf';

const timestamp = new Date().toISOString().replace(/[:.]/g, '-').slice(0, 19);
const safeTitle = (title || type).replace(/[^\u0600-\u06FFa-zA-Z0-9\s]/g, '').trim().slice(0, 50);
const outputFilename = `${timestamp}_${safeTitle}.md`;

return [{ json: { ...$input.first().json, type, outputFilename, timestamp } }];

