const typeData = $('🔍 تحديد نوع الرابط').first().json;
const jinaData = $('🌐 جلب المحتوى (Jina Premium)').first().json;
const aiData = $input.first().json;

const content = jinaData.body || jinaData.data || '';
const summary = aiData.response || '';
const wordCount = content.split(/\s+/).length;

const markdown = `---
title: "${typeData.title || typeData.url}"
url: ${typeData.url}
type: ${typeData.type}
date: ${typeData.timestamp}
words: ${wordCount}
source_file: ${typeData.fileName}
---

# ${typeData.title || 'محتوى من: ' + typeData.url}

**المصدر:** ${typeData.url}  
**النوع:** ${typeData.type}  
**التاريخ:** ${new Date(typeData.timestamp).toLocaleDateString('ar-SA')}  
**الملف الأصلي:** ${typeData.fileName}

---

## 📋 الملخص الذكي

${summary}

---

## 📄 المحتوى الكامل

${content}
`;

return [{ json: { ...typeData, markdown, wordCount } }];

// حفظ ملف Markdown ونقل الملف الأصلي عبر File API
const FILE_API = 'http://host.docker.internal:8765';
const { markdown, outputFilename, filePath, fileName } = $input.first().json;

// حفظ ملف Markdown في knowledge_inbox
try {
  await $helpers.httpRequest({
    method: 'POST',
    url: `${FILE_API}/write`,
    body: {
      path: `D:\\SaleHSaaS3\\knowledge_inbox\\${outputFilename}`,
      content: markdown
    },
    json: true
  });
} catch(e) {
  throw new Error('فشل حفظ ملف Markdown: ' + e.message);
}

// نقل الملف الأصلي إلى url_processed
try {
  await $helpers.httpRequest({
    method: 'POST',
    url: `${FILE_API}/move`,
    body: {
      source: filePath,
      destination: `D:\\SaleHSaaS3\\url_processed\\${fileName}`
    },
    json: true
  });
} catch(e) {
  // تسجيل الخطأ لكن لا نوقف التنفيذ
  console.log('تحذير: فشل نقل الملف: ' + e.message);
}

return [{ json: {
  ...($input.first().json),
  savedTo: `D:\\SaleHSaaS3\\knowledge_inbox\\${outputFilename}`,
  movedFrom: filePath,
  success: true
}}];

const data = $input.first().json;
console.log(`✅ تمت معالجة: ${data.fileName} → ${data.outputFilename} (${data.wordCount} كلمة)`);
return [{ json: {
  success: true,
  sourceFile: data.fileName,
  outputFile: data.outputFilename,
  savedTo: data.savedTo,
  url: data.url,
  type: data.type,
  words: data.wordCount,
  timestamp: new Date().toISOString()
}}];
